    <script>
      (function () {
        var KEY = 'arih:global-autoplay-preference';
        try {
          var raw = sessionStorage.getItem(KEY);
          if (raw !== 'true' && raw !== 'false') return;
          var enabled = raw === 'true';
          document.documentElement.dataset.autoplayEnabled = enabled ? 'true' : 'false';
          document.querySelectorAll('global-play-preference').forEach(function (el) {
            el.dataset.autoplayEnabled = enabled ? 'true' : 'false';
            var btn = el.querySelector('.global-play-pause__button');
            var play = el.querySelector('.global-play-pause__button-icon.icon-play');
            var pause = el.querySelector('.global-play-pause__button-icon.icon-pause');
            var text = el.querySelector('.global-play-pause__button-text');
            var lp = el.dataset.labelPause || 'Pause autoplay';
            var le = el.dataset.labelEnable || 'Enable autoplay';
            if (!btn || !play || !pause || !text) return;
            if (enabled) {
              play.hidden = true;
              pause.hidden = false;
              text.textContent = lp;
              btn.setAttribute('aria-pressed', 'true');
              btn.setAttribute('aria-label', lp);
            } else {
              play.hidden = false;
              pause.hidden = true;
              text.textContent = le;
              btn.setAttribute('aria-pressed', 'false');
              btn.setAttribute('aria-label', le);
            }
          });
        } catch (e) {}
      })();
